 var username = context.getVariable("private.username");
var password = context.getVariable("private.password");

// Pure JavaScript Base64 encoding function
function base64Encode(str) {
    var b64 = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
    var o1, o2, o3, h1, h2, h3, h4, bits, i = 0, ac = 0, enc = "", tmp_arr = [];

    if (!str) {
        return str;
    }

    do {
        o1 = str.charCodeAt(i++);
        o2 = str.charCodeAt(i++);
        o3 = str.charCodeAt(i++);

        bits = o1 << 16 | o2 << 8 | o3;

        h1 = bits >> 18 & 0x3f;
        h2 = bits >> 12 & 0x3f;
        h3 = bits >> 6 & 0x3f;
        h4 = bits & 0x3f;

        tmp_arr[ac++] = b64.charAt(h1) + b64.charAt(h2) + b64.charAt(h3) + b64.charAt(h4);
    } while (i < str.length);

    enc = tmp_arr.join('');

    var r = str.length % 3;

    return (r ? enc.slice(0, r - 3) : enc) + '==='.slice(r || 3);
}

if (username && password) {
    var credentials = username + ":" + password;
    var base64Credentials = base64Encode(credentials);

    context.setVariable("auth.header", "Basic " + base64Credentials);
} else {
    context.setVariable("auth.header", "CREDENTIALS_NOT_FOUND");
}
